export const slidesRaw = "%%%SLIDE 1 cover%%%\n<div class=\"cover-deco\"><span class=\"dot\"></span><span class=\"dot\"></span><span class=\"dot\"></span></div>\n<h1><em>Claude Code</em><br>Advanced</h1>\n<div style=\"display:flex; gap:40px; align-items:baseline; margin-top:24px;\">\n  <div>\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:11px; letter-spacing:0.16em; text-transform:uppercase; color:var(--accent); margin-bottom:6px;\">Co-authors</div>\n    <div style=\"font-size:20px; color:#fafafa;\">Paul Cailly & Claude</div>\n  </div>\n  <div>\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:11px; letter-spacing:0.16em; text-transform:uppercase; color:var(--accent); margin-bottom:6px;\">Date</div>\n    <div style=\"font-size:20px; color:#fafafa;\">April 22, 2026</div>\n  </div>\n</div>\n%%%SLIDE 2%%%\n<h1>Guidelines</h1>\n<div class=\"grid cols-2 gap-lg\" style=\"margin-top:28px;\">\n  <div class=\"card accent\">\n    <div class=\"card-title\">✋ Be present</div>\n    <div class=\"card-body\"><strong style=\"color:var(--accent)\">No Slack</strong>, give your full attention to the group.</div>\n  </div>\n  <div class=\"card accent\">\n    <div class=\"card-title\">🤝 Belong</div>\n    <div class=\"card-body\"><strong style=\"color:var(--accent)\">Engage</strong>, <strong style=\"color:var(--accent)\">share</strong> your thoughts, <strong style=\"color:var(--accent)\">ask</strong> questions, and support each other.</div>\n  </div>\n  <div class=\"card accent\">\n    <div class=\"card-title\">😁 Be at ease</div>\n    <div class=\"card-body\"><strong style=\"color:var(--accent)\">No judgment</strong>, what happens here stays here. Feel free to experiment and learn.</div>\n  </div>\n  <div class=\"card accent\">\n    <div class=\"card-title\">🎯 Goal</div>\n    <div class=\"card-body\">Everyone should get <strong style=\"color:var(--accent)\">3 things</strong> to try tomorrow.</div>\n  </div>\n</div>\n\n%%%SLIDE 3%%%\n<h1>Sources</h1>\n<div class=\"grid cols-2 gap-lg\">\n  <div>\n    <h3>Primary</h3>\n    <ul>\n      <li>My daily driver, fails & wins</li>\n      <li>Anthropic docs & engineering blog</li>\n      <li>Claude Code team posts, leaked skills</li>\n      <li>Building these slides with Claude Code</li>\n    </ul>\n  </div>\n  <div>\n    <h3>Talented people</h3>\n    <ul>\n      <li>John Lindquist <span class=\"text-muted\">— egghead.io · DX at Vercel</span></li>\n      <li>Andrej Karpathy <span class=\"text-muted\">— co-founder OpenAI</span></li>\n      <li>Matt Pocock <span class=\"text-muted\">— TypeScript & AI educator</span></li>\n      <li>Elie Schoppik <span class=\"text-muted\">— Anthropic</span></li>\n    </ul>\n  </div>\n</div>\n<h3 class=\"mt-lg\">Collective</h3>\n<div style=\"display:flex; gap:10px; flex-wrap:wrap;\">\n  <span class=\"pill\" style=\"color:#fafafa; border-color:#555\">r/ClaudeAI</span>\n  <span class=\"pill\" style=\"color:#fafafa; border-color:#555\">X / Twitter</span>\n  <span class=\"pill\" style=\"color:#fafafa; border-color:#555\">awesome-claude-code</span>\n  <span class=\"pill\" style=\"color:#fafafa; border-color:#555\">obra/superpowers</span>\n  <span class=\"pill\" style=\"color:#fafafa; border-color:#555\">rtk-ai/rtk</span>\n</div>\n\n%%%SLIDE 4%%%\n<h1>Claude <em>vs</em> Claude Code</h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">🧠</span>Claude</div>\n    <div class=\"card-label\">The model</div>\n    <div style=\"margin-top:14px; display:flex; flex-direction:column; gap:8px;\">\n      <div style=\"display:flex; align-items:center; gap:10px;\"><span class=\"pill solid\">OPUS</span><span style=\"font-size:13px; color:var(--muted)\">heavy reasoning, planning, critical review</span></div>\n      <div style=\"display:flex; align-items:center; gap:10px;\"><span class=\"pill accent\">SONNET</span><span style=\"font-size:13px; color:var(--muted)\">workhorse, daily code</span></div>\n      <div style=\"display:flex; align-items:center; gap:10px;\"><span class=\"pill\">HAIKU</span><span style=\"font-size:13px; color:var(--muted)\">fast, small tasks, exploration</span></div>\n    </div>\n  </div>\n  <div class=\"vs-divider\">vs</div>\n  <div class=\"vs-side right\">\n    <div class=\"card-title\" style=\"color:var(--blue)\"><span style=\"font-size:1.2em\">📚</span>Claude Code</div>\n    <div class=\"card-label\">A platform</div>\n    <div style=\"margin-top:14px; display:flex; flex-direction:column; gap:8px; font-size:13px; color:var(--muted);\">\n      <div>→ CLI, hooks, skills, MCP</div>\n      <div>→ Configurable runtime</div>\n      <div>→ Orchestration surface</div>\n      <div style=\"color:var(--accent); font-family:'JetBrains Mono',monospace; font-size:12px; margin-top:8px;\">not an app</div>\n    </div>\n  </div>\n</div>\n\n%%%SLIDE 5%%%\n<div style=\"display:flex; gap:32px; align-items:flex-start;\">\n  <div style=\"flex:1;\">\n    <div style=\"display:flex; gap:0;\">\n      <div style=\"color:var(--accent); font-size:120px; line-height:0.7; font-family:'Fraunces',serif; opacity:0.4;\">“</div>\n      <blockquote style=\"border:none; padding:16px 0 0 0; font-size:30px; line-height:1.35; margin:0;\">\n        Using Claude Code out-of-the-box is like using <em>VS Code with zero extensions</em>. You're technically using it, but fundamentally missing it.\n      </blockquote>\n    </div>\n    <div style=\"display:flex; justify-content:flex-end; margin-top:16px;\">\n      <div style=\"color:var(--accent); font-size:120px; line-height:0.3; font-family:'Fraunces',serif; opacity:0.4; transform:rotate(180deg);\">“</div>\n    </div>\n    <div style=\"margin-top:24px; padding-top:16px; border-top:1px solid var(--border); display:flex; gap:16px; align-items:center;\">\n      <div>\n        <div style=\"font-size:20px; color:#fafafa;\">John Lindquist</div>\n        <div style=\"font-size:15px; color:var(--muted);\">Co-founder egghead.io · DX at Vercel</div>\n      </div>\n    </div>\n  </div>\n</div>\n%%%SLIDE 6%%%\n<h1>The 3 platform layers</h1>\n<div class=\"layers\">\n  <div class=\"layer\">\n    <div class=\"layer-num\">LAYER 01</div>\n    <div><span class=\"layer-name\">Behavioral</span><span class=\"layer-name-sub\">reprogram the identity</span></div>\n    <div class=\"layer-tags\">system prompts · sub-agents</div>\n  </div>\n  <div class=\"layer\">\n    <div class=\"layer-num\">LAYER 02</div>\n    <div><span class=\"layer-name\">Environment</span><span class=\"layer-name-sub\">runtime contexts</span></div>\n    <div class=\"layer-tags\">CLI flags · permissions · settings · isolation</div>\n  </div>\n  <div class=\"layer\">\n    <div class=\"layer-num\">LAYER 03</div>\n    <div><span class=\"layer-name\">External</span><span class=\"layer-name-sub\">extension points</span></div>\n    <div class=\"layer-tags\">MCP · hooks · skills · plugins</div>\n  </div>\n</div>\n\n%%%SLIDE 7%%%\n<h1>The pattern that sums it up</h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">✅</span>By default</div>\n    <div class=\"card-label\">Conventions</div>\n    <div style=\"margin-top:14px; font-family:'JetBrains Mono',monospace; font-size:13px; color:var(--text-soft); line-height:1.9;\">\n      <div>→ <code>CLAUDE.md</code> auto-loaded</div>\n      <div>→ MCP schemas loaded</div>\n      <div>→ Settings picked up</div>\n      <div>→ Hooks registered</div>\n    </div>\n  </div>\n  <div class=\"vs-divider\">↔</div>\n  <div class=\"vs-side right\" style=\"border-left-color:var(--accent)\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">⚡</span>By choice</div>\n    <div class=\"card-label\">Escape hatches</div>\n    <div style=\"margin-top:14px; font-family:'JetBrains Mono',monospace; font-size:12px; color:var(--text-soft); line-height:1.9;\">\n      <div>→ <code>--setting-sources \"\"</code> <span style=\"color:var(--text-soft)\">ignore all CLAUDE.md</span></div>\n      <div>→ <code>--strict-mcp-config</code> <span style=\"color:var(--text-soft)\">lock MCP sources</span></div>\n      <div>→ <code>--bare -p</code> <span style=\"color:var(--text-soft)\">CI mode, no hooks/MCP</span></div>\n      <div>→ <code>--agent &lt;name&gt;</code> <span style=\"color:var(--text-soft)\">run as sub-agent</span></div>\n    </div>\n  </div>\n</div>\n\n%%%SLIDE 8%%%\n<h1>One-liner to remember</h1>\n<blockquote style=\"font-size:32px; line-height:1.3;\">\n  Claude Code isn't a <em>faster editor</em>.<br>\n  It's an orchestration system.\n</blockquote>\n<div class=\"grid cols-3 gap-lg\" style=\"margin-top:32px;\">\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">📖</span>\n    <div class=\"card-label\" style=\"font-size:17px;\">Context</div>\n    <div class=\"card-note\">what it knows</div>\n  </div>\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">🗺️</span>\n    <div class=\"card-label\" style=\"font-size:17px;\">Plans</div>\n    <div class=\"card-note\">what it intends</div>\n  </div>\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">🔄</span>\n    <div class=\"card-label\" style=\"font-size:17px;\">Loops</div>\n    <div class=\"card-note\">how it converges</div>\n  </div>\n</div>\n\n%%%SLIDE 9%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">🧹</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Setup & Hygiene</h1>\n  </div>\n</div>\n%%%SLIDE 10 question%%%\n<h2>What's in your <code>~/.claude/CLAUDE.md</code>?</h2>\n<h2>Who touched <code>settings.json</code> — and what did you change?</h2>\n%%%SLIDE 11%%%\n<h1>Custom statusline</h1>\n<div class=\"terminal\">\n  <div class=\"terminal-bar\">\n    <span class=\"terminal-dot red\"></span><span class=\"terminal-dot yellow\"></span><span class=\"terminal-dot green\"></span>\n    <span class=\"terminal-title\">~/projects/slides</span>\n  </div>\n  <div class=\"terminal-body\"><span class=\"prompt\">›</span> <span class=\"highlight\">/statusline show folder, git branch, model name, context bar</span>\n\n<span class=\"status\">✓</span> statusline configured\n─────────────────────────────────────────────────────────────\n <span class=\"value\">slides</span> · <span class=\"value\">feat/color-mode</span> · <span class=\"value\">sonnet-4.5</span> · <span class=\"value\">ctx 42%</span> · <span class=\"comment\">3 uncommitted</span>\n</div>\n</div>\n<div class=\"grid cols-5 gap-sm\" style=\"margin-top:8px;\">\n  <div class=\"card compact text-center\"><div class=\"card-num\">MODEL</div></div>\n  <div class=\"card compact text-center\"><div class=\"card-num\">FOLDER</div></div>\n  <div class=\"card compact text-center\"><div class=\"card-num\">BRANCH</div></div>\n  <div class=\"card compact text-center\"><div class=\"card-num\">UNCOMMITTED</div></div>\n  <div class=\"card compact text-center\"><div class=\"card-num\">CONTEXT %</div></div>\n</div>\n\n%%%SLIDE 12%%%\n<h1>CLAUDE.md · 3 scopes</h1>\n<div class=\"tree\">\n<div class=\"tree-row hl\">~/.claude/<strong>CLAUDE.md</strong> <span class=\"tree-badge\">GLOBAL</span><span class=\"tree-comment\">personal preferences</span></div>\n<div class=\"tree-row\"><span class=\"tree-indent\">│</span></div>\n<div class=\"tree-row hl\"><span class=\"tree-indent\">project/</span></div>\n<div class=\"tree-row hl\"><span class=\"tree-indent\">├── </span><strong>CLAUDE.md</strong> <span class=\"tree-badge\">PROJECT</span><span class=\"tree-comment\">team conventions, versioned</span></div>\n<div class=\"tree-row\"><span class=\"tree-indent\">├── package.json</span></div>\n<div class=\"tree-row\"><span class=\"tree-indent\">└── src/</span></div>\n<div class=\"tree-row\"><span class=\"tree-indent\">    ├── auth/</span></div>\n<div class=\"tree-row\"><span class=\"tree-indent\">    └── streaming/</span></div>\n<div class=\"tree-row hl\"><span class=\"tree-indent\">        └── </span><strong>CLAUDE.md</strong> <span class=\"tree-badge\">PATH</span><span class=\"tree-comment\">loaded on read</span></div>\n</div>\n<div class=\"callout\">The path-scoped file doesn't pollute other sessions. Claude only reads it when it touches that directory.</div>\n\n%%%SLIDE 13%%%\n<h1>settings.json · life-changing flags</h1>\n<div class=\"grid cols-2 gap-sm\">\n  <div class=\"card accent\">\n    <div class=\"card-num\">cleanupPeriodDays: 365</div>\n    <div class=\"card-body\"><strong>Default: 30.</strong> Without this, <code>/resume</code> and <code>/insights</code> only surface the last 30 days of sessions.</div>\n  </div>\n  <div class=\"card accent\">\n    <div class=\"card-num\">MAX_OUTPUT_TOKENS: 150000</div>\n    <div class=\"card-body\"><strong>Default: 30k.</strong> Which means build logs and test output get truncated when they matter most.</div>\n  </div>\n  <div class=\"card accent\">\n    <div class=\"card-num\">CLAUDE_AUTOCOMPACT_PCT_OVERRIDE: 75</div>\n    <div class=\"card-body\"><strong>Default: 95%.</strong> Quality degrades well before 95. Compact earlier, think clearer.</div>\n  </div>\n  <div class=\"card accent\">\n    <div class=\"card-num\">attribution.commit: \"\"</div>\n    <div class=\"card-body\"><strong>Default: on.</strong> Empty string drops the Claude co-author line from every commit.</div>\n  </div>\n</div>\n\n%%%SLIDE 14%%%\n<h1>Reflex commands</h1>\n<div class=\"kbd-list\">\n  <div class=\"kbd-row\"><span class=\"kbd\">/context</span><span class=\"kbd-desc\">see current state</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/clear</span><span class=\"kbd-desc\">between unrelated tasks</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/insights</span><span class=\"kbd-desc\">roasts your patterns</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">Ctrl+S</span><span class=\"kbd-desc\">stash the prompt</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">Shift+Tab</span><span class=\"kbd-desc\">cycle normal / auto-accept / plan</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">Esc</span><span class=\"kbd-desc\">interrupt generation</span></div>\n</div>\n<div class=\"callout neutral\"><strong>Rule of thumb:</strong> after 2 failed fixes on the same issue, <code>/clear</code> and restart fresh.</div>\n\n%%%SLIDE 15%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">🧠</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Context Engineering</h1>\n  </div>\n</div>\n%%%SLIDE 16%%%\n<h1>zsh aliases · one binary, many personalities</h1>\n<div class=\"personas\">\n  <div class=\"persona\">\n    <div class=\"persona-alias\">x</div>\n    <div class=\"persona-desc\"><strong>Bypass mode</strong>--dangerously-skip-permissions</div>\n  </div>\n  <div class=\"persona\">\n    <div class=\"persona-alias\">h</div>\n    <div class=\"persona-desc\"><strong>Quick & cheap</strong>--model claude-haiku-4-5</div>\n  </div>\n  <div class=\"persona\">\n    <div class=\"persona-alias\">cdi</div>\n    <div class=\"persona-desc\"><strong>Diagrams loaded</strong>preloads <code>.claude/memory/diagrams/*</code></div>\n  </div>\n  <div class=\"persona\">\n    <div class=\"persona-alias\">rv</div>\n    <div class=\"persona-desc\"><strong>Reviewer</strong>read-only tools, senior reviewer prompt</div>\n  </div>\n</div>\n\n```bash\nalias cdi=\"claude --append-system-prompt \\\"$(cat .claude/memory/diagrams/*.md)\\\"\"\nalias rv=\"claude --system-prompt 'senior code reviewer' --allowed-tools 'Read,Grep,Glob'\"\n```\n\n%%%SLIDE 17 question%%%\n<h2>How many lines is your CLAUDE.md?</h2>\n<h2>How often do you re-read it?</h2>\n\n%%%SLIDE 18%%%\n<h1>The facts</h1>\n<div class=\"grid cols-3 gap-lg\" style=\"margin:20px 0;\">\n  <div class=\"card text-center\" style=\"padding:24px 14px;\">\n    <div class=\"stat-num\">150<span style=\"color:var(--muted); font-size:0.5em;\">—</span>200</div>\n    <div class=\"stat-label\">instructions followed consistently</div>\n  </div>\n  <div class=\"card text-center\" style=\"padding:24px 14px;\">\n    <div class=\"stat-num\">~50</div>\n    <div class=\"stat-label\">already used by the system prompt</div>\n  </div>\n  <div class=\"card text-center\" style=\"padding:24px 14px;\">\n    <div class=\"stat-num\" style=\"color:var(--red)\">-3%</div>\n    <div class=\"stat-label\">LLM-written CLAUDE.md</div>\n    <div class=\"stat-delta neg\">+20% cost</div>\n  </div>\n</div>\n<div class=\"callout\"><strong>ETH Zürich 2026:</strong> hand-written CLAUDE.md improve task success by +4%. Machine-generated ones make it worse.</div>\n\n%%%SLIDE 19%%%\n<h1>CLAUDE.md rules</h1>\n<div class=\"grid cols-2 gap-sm\">\n  <div class=\"card accent\"><div class=\"card-num\">RULE 01</div><div class=\"card-label\">Under 200 lines</div><div class=\"card-body\">Under 2000 tokens. If you're over, you're guessing.</div></div>\n  <div class=\"card accent\"><div class=\"card-num\">RULE 02</div><div class=\"card-label\">Relevance test</div><div class=\"card-body\">\"If I remove this, does Claude make a mistake?\" No → remove it.</div></div>\n  <div class=\"card accent\"><div class=\"card-num\">RULE 03</div><div class=\"card-label\">Positive over negative</div><div class=\"card-body\"><code>Do NOT use semicolons</code> activates the concept. Say <code>Use no-semicolons ESLint rule</code> instead.</div></div>\n  <div class=\"card accent\"><div class=\"card-num\">RULE 04</div><div class=\"card-label\">Don't bold everything</div><div class=\"card-body\">If all 10 rules are IMPORTANT, none of them are.</div></div>\n</div>\n<div class=\"callout\"><strong>Rule 05 —</strong> No <code>@-mentions</code> of big files. Progressive disclosure: tell Claude <em>where</em> to look, not what's inside.</div>\n\n%%%SLIDE 20%%%\n<h1>Game-changer · Mermaid diagrams</h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\" style=\"border-left-color:var(--red)\">\n    <div class=\"card-title\" style=\"color:var(--red)\"><span style=\"font-size:1.2em\">❌</span>Without</div>\n    <div class=\"card-label\">Every session</div>\n    <div class=\"card-body\" style=\"margin-top:10px;\">Claude greps 50 files, reads 10 to 15, rebuilds understanding. <strong>Every. Single. Time.</strong></div>\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:11px; color:var(--muted); margin-top:10px;\">→ slow · token-hungry · inconsistent</div>\n  </div>\n  <div class=\"vs-divider\">→</div>\n  <div class=\"vs-side right\" style=\"border-left-color:var(--green)\">\n    <div class=\"card-title\" style=\"color:var(--green)\"><span style=\"font-size:1.2em\">✅</span>With</div>\n    <div class=\"card-label\">Preloaded diagrams</div>\n    <div class=\"card-body\" style=\"margin-top:10px;\"><code>.claude/memory/diagrams/*.md</code> in Mermaid. 3–6× more token-efficient than prose.</div>\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:11px; color:var(--muted); margin-top:10px;\">→ instant · cheap · consistent</div>\n  </div>\n</div>\n\n%%%SLIDE 21%%%\n<h1>What to diagram</h1>\n<div class=\"grid cols-5 gap-sm\">\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">🔒</span>\n    <div class=\"card-label\" style=\"font-size:14px;\">Auth flow</div>\n  </div>\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">🔀</span>\n    <div class=\"card-label\" style=\"font-size:14px;\">Microservices</div>\n  </div>\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">🗄️</span>\n    <div class=\"card-label\" style=\"font-size:14px;\">Data schema</div>\n  </div>\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">⚡</span>\n    <div class=\"card-label\" style=\"font-size:14px;\">Event flow</div>\n  </div>\n  <div class=\"card compact text-center\">\n    <span style=\"font-size:1.2em\">🔄</span>\n    <div class=\"card-label\" style=\"font-size:14px;\">State machines</div>\n  </div>\n</div>\n<div class=\"callout\"><strong>Pro tip:</strong> event flow (Kafka, pub/sub) pays off instantly. Subscription lifecycles, playlist state machines too.</div>\n\n%%%SLIDE 22%%%\n<h1>Concrete example</h1>\n<div style=\"display:grid; grid-template-columns:2fr 1fr; gap:28px;\">\n  <div>\n    <h3>Rendered</h3>\n\n```mermaid\nstateDiagram-v2\n    [*] --> Slide1: load\n    Slide1 --> SlideN: ArrowRight / Space\n    SlideN --> SlideN: ArrowRight / Space\n    SlideN --> SlideN: ArrowLeft\n    SlideN --> Slide1: Home\n    SlideN --> SlideLast: End\n    SlideN --> Fullscreen: F\n    Fullscreen --> SlideN: Esc\n    SlideN --> JumpTo: type number\n    JumpTo --> SlideN: Enter\n```\n\n  </div>\n  <div>\n    <h3>Source</h3>\n    <pre style=\"font-size:14px !important; line-height:1.7;\"><code>stateDiagram-v2\n    [*] --> Slide1: load\n    Slide1 --> SlideN: ArrowRight / Space\n    SlideN --> SlideN: ArrowRight / Space\n    SlideN --> SlideN: ArrowLeft\n    SlideN --> Slide1: Home\n    SlideN --> SlideLast: End\n    SlideN --> Fullscreen: F\n    Fullscreen --> SlideN: Esc\n    SlideN --> JumpTo: type number\n    JumpTo --> SlideN: Enter</code></pre>\n  </div>\n</div>\n<div class=\"callout neutral\" style=\"margin-top:10px;\"><strong>This is the actual navigation logic of the deck you’re watching.</strong> Mermaid state diagrams map directly to UI behavior.</div>\n%%%SLIDE 23%%%\n<h1>Preloading</h1>\n\n```bash\nalias cdi=\"claude --append-system-prompt \\\"$(cat .claude/memory/diagrams/*.md)\\\"\"\n```\n\n<div class=\"vs\">\n  <div class=\"vs-side left\" style=\"border-left-color:var(--red)\">\n    <div class=\"card-title\" style=\"color:var(--red)\">Cost</div>\n    <div class=\"stat-num\" style=\"font-size:48px; color:var(--red)\">+5–15k</div>\n    <div class=\"stat-label\">tokens at startup</div>\n  </div>\n  <div class=\"vs-divider\">→</div>\n  <div class=\"vs-side right\" style=\"border-left-color:var(--green)\">\n    <div class=\"card-title\" style=\"color:var(--green)\">Gain</div>\n    <div class=\"card-body\" style=\"font-size:16px; margin-top:6px;\">Zero exploration.<br>Edits right the first time.<br>Consistent architectural reasoning.</div>\n  </div>\n</div>\n\n%%%SLIDE 24%%%\n<h1>When to generate them</h1>\n<div class=\"grid cols-3 gap-lg\">\n  <div class=\"card\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">📖</span>Existing code</div>\n    <div class=\"card-label\">Batch job</div>\n    <div class=\"card-body\">Sub-agent explores the codebase, produces initial diagrams. You review and trim by hand.</div>\n  </div>\n  <div class=\"card\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">🔀</span>Greenfield</div>\n    <div class=\"card-label\">On PR merge</div>\n    <div class=\"card-body\">GitHub Action updates impacted diagrams automatically. Diagram drift stays bounded.</div>\n  </div>\n  <div class=\"card\" style=\"border-left:2px solid var(--accent);\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">🔄</span>Multi-purpose</div>\n    <div class=\"card-label\">One source, many outputs</div>\n    <div class=\"card-body\">Same diagrams feed onboarding, security audits, architecture reviews, and next-session context.</div>\n  </div>\n</div>\n\n%%%SLIDE 25%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">✨</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Skills</h1>\n  </div>\n</div>\n%%%SLIDE 26%%%\n<div style=\"display:grid; grid-template-columns: 1fr 1fr; gap:40px; align-items:center;\">\n  <div>\n    <h1 style=\"font-size:48px;\">Progressive<br>disclosure</h1>\n    <blockquote style=\"font-size:22px;\">\n      Don't tell Claude everything he might want to know. <em>Tell him where to look.</em>\n    </blockquote>\n  </div>\n  <div>\n    <div class=\"flow-v\">\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">01</span><div class=\"flow-v-body\"><strong>Skills</strong> · invoked when relevant</div></div>\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">02</span><div class=\"flow-v-body\"><strong>Diagrams</strong> · loaded on demand</div></div>\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">03</span><div class=\"flow-v-body\"><strong>Path CLAUDE.md</strong> · read when entered</div></div>\n    </div>\n  </div>\n</div>\n\n%%%SLIDE 27 question%%%\n<h2>Who has written their own skill?</h2>\n<h2>What's holding you back?</h2>\n\n%%%SLIDE 28%%%\n<h1>Skill = SKILL.md + frontmatter</h1>\n<pre><code class=\"language-yaml\">---\nname: deploy\ndescription: Deploy the app to production\ncontext: fork              <span style=\"color:var(--accent)\"># ← isolates in a sub-agent</span>\ndisable-model-invocation: true  <span style=\"color:var(--accent)\"># ← human-only</span>\ntools: [bash, read]\n---\n\n## Deploy procedure\n1. Check health endpoint\n2. Drain traffic\n...\n</code></pre>\n<div class=\"grid cols-2 gap-sm\">\n  <div class=\"card compact\"><div class=\"card-title\"><span style=\"font-size:1.2em\">📦</span>Open standard</div><div class=\"card-body\">\"Agent Skills\", compatible with Cursor and other AI tools</div></div>\n  <div class=\"card compact\"><div class=\"card-title\"><span style=\"font-size:1.2em\">🔄</span>Supersedes</div><div class=\"card-body\">Legacy <code>.claude/commands/</code></div></div>\n</div>\n\n%%%SLIDE 29%%%\n<h1>The 3 levers that matter</h1>\n<div class=\"grid cols-3 gap-lg\">\n  <div class=\"card\">\n    <span style=\"font-size:1.2em\">🔀</span>\n    <div class=\"card-num\">context: fork</div>\n    <div class=\"card-label\">Protects parent</div>\n    <div class=\"card-body\">Runs in a sub-agent. Main context stays clean. The built-in <code>/batch</code> uses this.</div>\n  </div>\n  <div class=\"card\">\n    <span style=\"font-size:1.2em\">👤</span>\n    <div class=\"card-num\">disable-model-invocation</div>\n    <div class=\"card-label\">Human only</div>\n    <div class=\"card-body\">For risky ops: deploy, delete, anything irreversible. No accidental auto-invoke.</div>\n  </div>\n  <div class=\"card\">\n    <span style=\"font-size:1.2em\">⚡</span>\n    <div class=\"card-num\">description</div>\n    <div class=\"card-label\">Auto-invocation</div>\n    <div class=\"card-body\">Claude reads the description, matches the context, invokes without being asked.</div>\n  </div>\n</div>\n\n%%%SLIDE 30%%%\n<h1>Bundled skills</h1>\n<div class=\"grid cols-5 gap-sm\">\n  <div class=\"card compact text-center\"><span style=\"font-size:1.2em\">📚</span><div class=\"card-num\">/simplify</div><div class=\"card-note\" style=\"font-size:11px;\">3 parallel refactor agents</div></div>\n  <div class=\"card compact text-center\"><span style=\"font-size:1.2em\">🔀</span><div class=\"card-num\">/batch</div><div class=\"card-note\" style=\"font-size:11px;\">split-merge + worktrees</div></div>\n  <div class=\"card compact text-center\"><span style=\"font-size:1.2em\">⚠️</span><div class=\"card-num\">/debug</div><div class=\"card-note\" style=\"font-size:11px;\">guided debug</div></div>\n  <div class=\"card compact text-center\"><span style=\"font-size:1.2em\">🔄</span><div class=\"card-num\">/loop</div><div class=\"card-note\" style=\"font-size:11px;\">polling</div></div>\n  <div class=\"card compact text-center\"><span style=\"font-size:1.2em\">💻</span><div class=\"card-num\">/claude-api</div><div class=\"card-note\" style=\"font-size:11px;\">API helper</div></div>\n</div>\n\n%%%SLIDE 31%%%\n<h1>Advanced patterns</h1>\n<div class=\"grid cols-3 gap-lg\">\n  <div class=\"card\">\n    <div class=\"card-num\">01 · SHELL INJECTION</div>\n    <div class=\"card-label\">Dynamic context</div>\n    <pre style=\"margin:10px 0 0; padding:10px 12px !important; font-size:11px !important;\"><code>Current branch:\n!git branch --show-current</code></pre>\n    <div class=\"card-note\" style=\"margin-top:8px;\">Claude only sees the output.</div>\n  </div>\n  <div class=\"card\">\n    <div class=\"card-num\">02 · SUB-AGENT + WORKTREE</div>\n    <div class=\"card-label\">Isolated execution</div>\n    <div class=\"card-body\" style=\"margin-top:10px;\">Run destructive skills without polluting the parent context. Blast-radius controlled.</div>\n  </div>\n  <div class=\"card\" style=\"border-left:2px solid var(--accent);\">\n    <div class=\"card-num\">03 · SKILLIFY</div>\n    <div class=\"card-label\">Meta-skill</div>\n    <div class=\"card-body\" style=\"margin-top:10px;\">Brainstorm a workflow. When it works: <em>\"turn this session into a reusable skill.\"</em></div>\n  </div>\n</div>\n\n%%%SLIDE 32%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">🔌</div>\n    <h1 style=\"font-size:80px; line-height:1;\">MCP</h1>\n  </div>\n</div>\n%%%SLIDE 33%%%\n<h1>Skills to try</h1>\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card\"><div class=\"card-num\"><span class=\"tag\">FLAGSHIP</span></div><div class=\"card-label\">obra/superpowers</div><div class=\"card-note\">TDD · debug · review — the most complete pack</div></div>\n  <div class=\"card\"><div class=\"card-num\">rtk-ai/rtk</div><div class=\"card-label\">Curated bundle</div><div class=\"card-note\">plugins and skills worth installing</div></div>\n  <div class=\"card\"><div class=\"card-num\">frontend-design</div><div class=\"card-label\">Design quality</div><div class=\"card-note\">kills generic AI UI aesthetics</div></div>\n  <div class=\"card\"><div class=\"card-num\">premortem</div><div class=\"card-label\">Pre-prod check</div><div class=\"card-note\">finds 20 failures before prod</div></div>\n  <div class=\"card\"><div class=\"card-num\">mutation-testing</div><div class=\"card-label\">Test the tests</div><div class=\"card-note\">injects bugs, checks if suite catches</div></div>\n  <div class=\"card\"><div class=\"card-num\">color-expert</div><div class=\"card-label\">Color science</div><div class=\"card-note\">ends the default purple/white</div></div>\n</div>\n\n%%%SLIDE 34 question%%%\n<h2>Which MCPs do you use daily?</h2>\n<h2>Which one disappointed you?</h2>\n\n%%%SLIDE 35%%%\n<h1>Skills <em>vs</em> MCP · the real tradeoff</h1>\n<table>\n  <thead>\n    <tr><th></th><th>MCP tool</th><th>Skill</th></tr>\n  </thead>\n  <tbody>\n    <tr><td><strong>Defined in</strong></td><td>Code + Zod schema</td><td>Markdown + YAML</td></tr>\n    <tr><td><strong>The agent</strong></td><td>calls it with typed args</td><td>reads, decides, chains actions</td></tr>\n    <tr><td><strong>Best for</strong></td><td>precise, repeatable workflow</td><td>multi-step, conditional, judgment</td></tr>\n    <tr><td><strong>Example</strong></td><td>compress file, query API</td><td>deploy procedure, debug session</td></tr>\n  </tbody>\n</table>\n<div class=\"grid cols-2 gap-sm\">\n  <div class=\"card info\"><div class=\"card-title\">THE RULE</div><div class=\"card-body\">Know exactly what will happen → <strong>MCP</strong>. Otherwise → <strong>Skill</strong>.</div></div>\n  <div class=\"card accent\"><div class=\"card-title\">IDEAL PATTERN</div><div class=\"card-body\">A skill that <strong>calls several MCP tools</strong> as it reasons through the steps.</div></div>\n</div>\n\n%%%SLIDE 36%%%\n<h1>The truth about code search</h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\" style=\"border-left-color:var(--green); padding:24px;\">\n    <div class=\"card-title\" style=\"color:var(--green)\">WINNER</div>\n    <div class=\"stat-num\" style=\"font-size:56px; color:var(--green)\">glob + grep</div>\n    <div class=\"card-body\" style=\"margin-top:14px;\">Agentic search works. Claude knows how to navigate your code.</div>\n  </div>\n  <div class=\"vs-divider\">&gt;</div>\n  <div class=\"vs-side right\" style=\"border-left-color:var(--red); padding:24px;\">\n    <div class=\"card-title\" style=\"color:var(--red)\">ABANDONED</div>\n    <div class=\"stat-num\" style=\"font-size:56px; color:var(--red)\">RAG</div>\n    <div class=\"card-body\" style=\"margin-top:14px;\">Code drifts. Permissions get complex. Vector DBs were tried, then dropped.</div>\n  </div>\n</div>\n<div class=\"callout\"><strong>For your code:</strong> just let Claude grep.</div>\n\n%%%SLIDE 37%%%\n<h1>MCPs that actually deliver</h1>\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card accent\"><div class=\"card-num\">Context7</div><div class=\"card-label\">Live docs</div><div class=\"card-note\">up-to-date library refs, stops hallucinated APIs</div></div>\n  <div class=\"card accent\"><div class=\"card-num\">Playwright MCP <span class=\"tag\">OFFICIAL</span></div><div class=\"card-label\">Browser eyes</div><div class=\"card-note\">Claude drives a browser, screenshots itself, iterates on UI</div></div>\n  <div class=\"card accent\"><div class=\"card-num\">Figma MCP</div><div class=\"card-label\">Design to code</div><div class=\"card-note\">reads the mockup, implements</div></div>\n  <div class=\"card\"><div class=\"card-num\">agent-browser <span class=\"tag\">VERCEL</span></div><div class=\"card-label\">Accessibility tree</div><div class=\"card-note\">200–400 tokens per DOM vs thousands for Chrome ext</div></div>\n  <div class=\"card\"><div class=\"card-num\">GitHub / GitLab</div><div class=\"card-label\">PRs, issues, reviews</div><div class=\"card-note\">the obvious default</div></div>\n  <div class=\"card\"><div class=\"card-num\">Jira / Notion / Linear</div><div class=\"card-label\">Docs & tickets</div><div class=\"card-note\">context retrieval across tools</div></div>\n</div>\n\n%%%SLIDE 38%%%\n<h1>The bloat trap</h1>\n<div style=\"display:grid; grid-template-columns: auto 1fr; gap:40px; align-items:center;\">\n  <div style=\"text-align:center;\">\n    <svg width=\"180\" height=\"180\" viewBox=\"0 0 180 180\">\n      <circle cx=\"90\" cy=\"90\" r=\"70\" fill=\"none\" stroke=\"#242424\" stroke-width=\"22\"/>\n      <circle cx=\"90\" cy=\"90\" r=\"70\" fill=\"none\" stroke=\"#c96868\" stroke-width=\"22\" stroke-dasharray=\"264 440\" transform=\"rotate(-90 90 90)\"/>\n      <circle cx=\"90\" cy=\"90\" r=\"70\" fill=\"none\" stroke=\"#d97757\" stroke-width=\"22\" stroke-dasharray=\"88 440\" stroke-dashoffset=\"-264\" transform=\"rotate(-90 90 90)\"/>\n      <text x=\"90\" y=\"86\" text-anchor=\"middle\" font-family=\"Fraunces\" font-size=\"30\" fill=\"#fafafa\">60%</text>\n      <text x=\"90\" y=\"108\" text-anchor=\"middle\" font-family=\"JetBrains Mono\" font-size=\"9\" letter-spacing=\"2\" fill=\"#888\">MCP SCHEMAS</text>\n    </svg>\n    <div class=\"donut-caption\">context budget · default load</div>\n  </div>\n  <div>\n    <div class=\"card danger\" style=\"margin-bottom:12px;\">\n      <div class=\"card-title\" style=\"color:var(--red)\">The problem</div>\n      <div class=\"card-body\">Every connected MCP burns tokens at startup — <strong>even when unused</strong>.</div>\n    </div>\n    <div class=\"card success\" style=\"margin-bottom:12px;\">\n      <div class=\"card-title\" style=\"color:var(--green)\">Solution 1</div>\n      <div class=\"card-body\">Disable MCPs that aren't relevant to the project.</div>\n    </div>\n    <div class=\"card success\">\n      <div class=\"card-title\" style=\"color:var(--green)\">Solution 2</div>\n      <div class=\"card-body\"><code>experimentalMCPCLI: true</code> — tools load on demand via <code>mcp__list</code> / <code>mcp__call</code>.</div>\n    </div>\n  </div>\n</div>\n\n%%%SLIDE 39%%%\n<h1>Custom MCP in 50 lines</h1>\n\n```typescript\nimport { tool, z } from \"mcpez\";\n\ntool(\"compress\", {\n  description: \"Compress a file or directory using tar and gzip\",\n  inputSchema: {\n    outputFileName: z.string().describe(\"Path ending in .tar.gz\"),\n    filesToCompress: z.array(z.string()),\n  },\n  async ({ outputFileName, filesToCompress }) => {\n    // your logic\n    return { content: [{ type: \"text\", text: \"Done\" }] };\n  },\n});\n```\n\n<div class=\"terminal\">\n  <div class=\"terminal-body\"><span class=\"prompt\">$</span> claude mcp add tools --scope project -- bun run .claude/mcp/index.ts\n<span class=\"status\">✓</span> registered · scope: project · 1 tool</div>\n</div>\n\n%%%SLIDE 40%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">🪝</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Hooks</h1>\n  </div>\n</div>\n%%%SLIDE 41%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-size:80px; margin-bottom:24px;\">☕</div>\n    <h1 style=\"font-size:72px; line-height:1.1;\">Short break</h1>\n    <p style=\"font-size:28px; color:var(--muted); margin-top:20px;\">Back in 10 minutes</p>\n  </div>\n</div>\n%%%SLIDE 42 question%%%\n<h2>Who has configured a hook?</h2>\n<h2>Has anyone been saved by a hook?</h2>\n\n%%%SLIDE 43%%%\n<h1>Hooks · the basics</h1>\n<div class=\"flow-h\">\n  <div class=\"flow-step\"><div class=\"flow-label\">01</div><div class=\"flow-title\">SessionStart</div><div class=\"flow-sub\">session boot</div></div>\n  <div class=\"flow-arrow\">→</div>\n  <div class=\"flow-step\"><div class=\"flow-label\">02</div><div class=\"flow-title\">PreToolUse</div><div class=\"flow-sub\">before tool call</div></div>\n  <div class=\"flow-arrow\">→</div>\n  <div class=\"flow-step\"><div class=\"flow-label\">03</div><div class=\"flow-title\">PostToolUse</div><div class=\"flow-sub\">after tool call</div></div>\n  <div class=\"flow-arrow\">→</div>\n  <div class=\"flow-step\"><div class=\"flow-label\">04</div><div class=\"flow-title\">Stop</div><div class=\"flow-sub\">end of turn</div></div>\n</div>\n<div class=\"callout neutral\"><strong>The hook receives JSON on stdin:</strong> <code>tool_name</code>, <code>tool_input</code>, <code>cwd</code>, <code>session_id</code>. Condition your script on any of these.</div>\n\n%%%SLIDE 44%%%\n<h1>Exit codes · the game-changer</h1>\n<div class=\"exit-codes\">\n  <div class=\"exit-code\">\n    <div class=\"exit-code-num\">0</div>\n    <div class=\"exit-code-label\">success</div>\n    <div class=\"exit-code-desc\">silent pass</div>\n  </div>\n  <div class=\"exit-code hero\">\n    <div class=\"exit-code-num\">2</div>\n    <div class=\"exit-code-label\">block</div>\n    <div class=\"exit-code-desc\">error returned to Claude → must fix</div>\n  </div>\n  <div class=\"exit-code\">\n    <div class=\"exit-code-num\">*</div>\n    <div class=\"exit-code-label\">other</div>\n    <div class=\"exit-code-desc\">non-blocking, verbose</div>\n  </div>\n</div>\n<div class=\"grid cols-2 gap-sm\">\n  <div class=\"card\"><div class=\"stat-num sm\">~70%</div><div class=\"stat-label\">CLAUDE.md followed</div></div>\n  <div class=\"card accent\"><div class=\"stat-num sm\" style=\"color:var(--green)\">100%</div><div class=\"stat-label\">blocking hook respected</div></div>\n</div>\n\n%%%SLIDE 45%%%\n<h1>Agent hooks <span class=\"tag\">NEW</span></h1>\n<p>Instead of a shell command, a sub-agent that can read files, grep, execute commands to decide.</p>\n\n```json\n{\n  \"hooks\": {\n    \"Stop\": [{\n      \"hooks\": [{\n        \"type\": \"agent\",\n        \"prompt\": \"Verify that all unit tests pass.\",\n        \"timeout\": 120\n      }]\n    }]\n  }\n}\n```\n\n<div class=\"callout neutral\"><strong>Timeout 60s default, up to 50 tool-use turns.</strong> Useful when verification needs judgment, not regex. For prod: command hooks remain preferred (deterministic).</div>\n\n%%%SLIDE 46%%%\n<h1>The killer pattern</h1>\n\n```mermaid\nflowchart LR\n    A[Claude says done] --> B{Type-check<br>Lint · Build}\n    B -->|pass| C[Auto commit]\n    B -->|fail| D[Exit 2<br>+ report]\n    D -->|Claude retries| A\n```\n\n```typescript\nif (result.exitCode !== 0) {\n  console.log(JSON.stringify({ decision: \"block\", reason: result.stdout }));\n  process.exit(2);\n}\nawait $`git add -A && git commit -m \"auto: task completed\"`;\n```\n\n<div class=\"callout\"><strong>Gotcha:</strong> <code>console.log</code> is the return channel. Debug via <code>console.error</code>.</div>\n\n%%%SLIDE 47%%%\n<h1>The 7 hooks that save your life</h1>\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card accent\"><div class=\"card-num\">01</div><div class=\"card-label\">Type-check stop</div><div class=\"card-note\">Lindquist pattern · the flagship</div></div>\n  <div class=\"card\"><div class=\"card-num\">02</div><div class=\"card-label\">Auto-format</div><div class=\"card-note\">prettier post Edit/Write</div></div>\n  <div class=\"card danger\"><div class=\"card-num\">03</div><div class=\"card-label\">Block destructive</div><div class=\"card-note\"><code>rm -rf</code>, <code>--force</code>, push to main</div></div>\n  <div class=\"card\"><div class=\"card-num\">04</div><div class=\"card-label\">TDD Guard</div><div class=\"card-note\">no secret test edits</div></div>\n  <div class=\"card\"><div class=\"card-num\">05</div><div class=\"card-label\">Force a lib</div><div class=\"card-note\">block <code>pip</code>, enforce <code>uv</code></div></div>\n  <div class=\"card\"><div class=\"card-num\">06</div><div class=\"card-label\">Big-file read</div><div class=\"card-note\">force <code>offset</code>/<code>limit</code></div></div>\n  <div class=\"card\" style=\"grid-column: span 3;\"><div class=\"card-num\">07</div><div class=\"card-label\">Stop + AskUserQuestion</div><div class=\"card-note\">keeps the human in the loop without retyping prompts</div></div>\n</div>\n\n%%%SLIDE 48%%%\n<h1>Team-shared hooks</h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">👥</span>settings.json</div>\n    <div class=\"card-label\">Versioned</div>\n    <div class=\"card-body\">Shared with the whole team. Everyone gets the same guardrails.</div>\n  </div>\n  <div class=\"vs-divider\">↔</div>\n  <div class=\"vs-side right\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">👤</span>settings.local.json</div>\n    <div class=\"card-label\">Personal</div>\n    <div class=\"card-body\">Your own rules. Not shared.</div>\n  </div>\n</div>\n<div class=\"callout\"><strong>Team leverage:</strong> enforce lint config, commit style, secret scanning before push. One hook written once → every dev protected. Scaled leverage.</div>\n\n%%%SLIDE 49%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">🤖</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Sub-agents</h1>\n  </div>\n</div>\n%%%SLIDE 50%%%\n<h1>Ralph loop</h1>\n\n```mermaid\nflowchart LR\n    A[Claude works] --> B[Stop hook]\n    B --> C{Tests · Lint · Build}\n    C -->|all pass| D[✓ Done]\n    C -->|any fail| A\n```\n\n<div class=\"callout\"><strong>Same exit-2 mechanic, pushed to the extreme.</strong> The hook refuses to let Claude stop until the build is green. You go make coffee; Claude converges.</div>\n\n%%%SLIDE 51 question%%%\n<h2>Who has run multiple Claudes in parallel?</h2>\n<h2>How do you avoid conflicts?</h2>\n\n%%%SLIDE 52%%%\n<h1>Sub-agents <em>vs</em> Agent Teams</h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">➡️</span>Sub-agent</div>\n    <div class=\"card-label\">Delegation</div>\n    <pre style=\"margin:12px 0; padding:12px !important; font-size:11px !important;\">parent\n  └─ child → result</pre>\n    <div class=\"card-body\">Parent spawns child, gets synthesized result back. Parent context stays clean.</div>\n  </div>\n  <div class=\"vs-divider\">vs</div>\n  <div class=\"vs-side right\" style=\"border-left-color:var(--blue)\">\n    <div class=\"card-title\" style=\"color:var(--blue)\"><span style=\"font-size:1.2em\">👥</span>Agent Team</div>\n    <div class=\"card-label\">Collaboration</div>\n    <pre style=\"margin:12px 0; padding:12px !important; font-size:11px !important;\">lead ⇄ member\n  ⇅      ⇅\nmember ⇄ member</pre>\n    <div class=\"card-body\">Peers talk, split, merge. Lead + members. P2P, not star.</div>\n  </div>\n</div>\n\n%%%SLIDE 53%%%\n<h1>The 3 built-ins</h1>\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card\">\n    <span style=\"font-size:1.2em\">👁️</span>\n    <div class=\"card-num\">EXPLORE <span class=\"pill\">HAIKU</span></div>\n    <div class=\"card-label\">Read-only · fast</div>\n    <div class=\"card-body\">Analyzes a codebase without touching anything.</div>\n  </div>\n  <div class=\"card\">\n    <span style=\"font-size:1.2em\">🗺️</span>\n    <div class=\"card-num\">PLAN <span class=\"pill\">READ-ONLY</span></div>\n    <div class=\"card-label\">Architecture</div>\n    <div class=\"card-body\">Proposes an implementation plan.</div>\n  </div>\n  <div class=\"card\">\n    <span style=\"font-size:1.2em\">▶️</span>\n    <div class=\"card-num\">GENERAL-PURPOSE</div>\n    <div class=\"card-label\">Full tools</div>\n    <div class=\"card-body\">Writes, runs, commits. The executor.</div>\n  </div>\n</div>\n\n```yaml\n---\nname: code-reviewer\ntools: Read, Grep, Glob\nmodel: haiku\nisolation: worktree\n---\n```\n\n%%%SLIDE 54%%%\n<h1>Explore → Plan → Execute</h1>\n<div class=\"flow-h\">\n  <div class=\"flow-step\">\n    <span style=\"font-size:1.2em\">👁️</span>\n    <div class=\"flow-title\">Explore</div>\n    <div class=\"flow-sub\">analyze <code>src/auth/</code></div>\n  </div>\n  <div class=\"flow-arrow\">→</div>\n  <div class=\"flow-step\">\n    <span style=\"font-size:1.2em\">🗺️</span>\n    <div class=\"flow-title\">Plan</div>\n    <div class=\"flow-sub\">design the refactor</div>\n  </div>\n  <div class=\"flow-arrow\">→</div>\n  <div class=\"flow-step\">\n    <span style=\"font-size:1.2em\">▶️</span>\n    <div class=\"flow-title\">Execute</div>\n    <div class=\"flow-sub\">ship the change</div>\n  </div>\n</div>\n<div class=\"callout\"><strong>Clean cognitive separation.</strong> Each phase lives in its own context. No cross-contamination between exploration noise and execution decisions.</div>\n\n%%%SLIDE 55%%%\n<h1>Git worktrees · rule #1</h1>\n<blockquote style=\"font-size:26px;\"><em>No shared branches.</em> Only worktrees.</blockquote>\n\n```bash\ngit worktree add ../project-auth   feature/auth\ngit worktree add ../project-tests  feature/tests\ngit worktree add ../project-docs   feature/docs\n```\n\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card accent text-center\"><span style=\"font-size:1.2em\">📁</span><div class=\"card-num\">project-auth</div><div class=\"card-note\">Claude #1</div></div>\n  <div class=\"card accent text-center\"><span style=\"font-size:1.2em\">📁</span><div class=\"card-num\">project-tests</div><div class=\"card-note\">Claude #2</div></div>\n  <div class=\"card accent text-center\"><span style=\"font-size:1.2em\">📁</span><div class=\"card-num\">project-docs</div><div class=\"card-note\">Claude #3</div></div>\n</div>\n<div class=\"callout\"><strong>Gotcha:</strong> <code>.env</code> isn't copied (it's gitignored). Create a <code>.worktreeinclude</code> at the root.</div>\n\n%%%SLIDE 56%%%\n<h1>Agent Teams <span class=\"tag\">OPUS 4.6+</span></h1>\n\n```mermaid\nflowchart TD\n    L[Lead] <-->|mailbox| A[Member A]\n    L <-->|mailbox| B[Member B]\n    L <-->|mailbox| C[Member C]\n    A <-->|P2P| B\n    B <-->|P2P| C\n```\n\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card\"><div class=\"stat-num sm\">3–5</div><div class=\"stat-label\">agents max</div></div>\n  <div class=\"card\"><div class=\"stat-num sm\">3–4×</div><div class=\"stat-label\">cost vs single</div></div>\n  <div class=\"card\"><div class=\"stat-num sm\">P2P</div><div class=\"stat-label\">via mailbox</div></div>\n</div>\n\n%%%SLIDE 57%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">📋</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Methodology</h1>\n  </div>\n</div>\n%%%SLIDE 58%%%\n<h1>Adversarial setup <span class=\"tag\">KILLER</span></h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\">\n    <div class=\"card-title\"><span class=\"icon-circle sm solid\">1</span>Agent 1</div>\n    <div class=\"card-label\">Implements</div>\n    <div class=\"card-body\">Writes the draft. Researches. Ships the first pass.</div>\n  </div>\n  <div class=\"vs-divider\">⇅</div>\n  <div class=\"vs-side right\" style=\"border-left-color:var(--red)\">\n    <div class=\"card-title\" style=\"color:var(--red)\"><span class=\"icon-circle sm\" style=\"background:rgba(201,104,104,0.1); color:var(--red)\">2</span>Agent 2</div>\n    <div class=\"card-label\">Critiques</div>\n    <div class=\"card-body\">Fact-checks. Challenges assumptions. Blocked until draft is done.</div>\n  </div>\n</div>\n<h3>Use cases</h3>\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card compact\"><div class=\"card-num\">RESEARCH</div><div class=\"card-note\">critic challenges sources</div></div>\n  <div class=\"card compact\"><div class=\"card-num\">CODE REVIEW</div><div class=\"card-note\">writer vs reviewer, against the plan</div></div>\n  <div class=\"card compact\"><div class=\"card-num\">TDD SPLIT</div><div class=\"card-note\">A writes tests, B writes code</div></div>\n</div>\n\n%%%SLIDE 59 question%%%\n<h2>Do you plan before coding?</h2>\n<h2>TDD? Specs?</h2>\n\n%%%SLIDE 60%%%\n<h1>Plan mode</h1>\n<div class=\"grid cols-2 gap-lg\">\n  <div>\n    <div class=\"kbd-row\" style=\"margin-bottom:14px;\"><span class=\"kbd\">Shift+Tab</span><span class=\"kbd-desc\">× 2 to enter plan mode</span></div>\n    <div class=\"card info\"><div class=\"card-title\">Read-only</div><div class=\"card-body\">No writes. No destructive tool calls. Claude explores and proposes.</div></div>\n  </div>\n  <div>\n    <div class=\"card accent\">\n      <div class=\"card-title\">Interview pattern <span class=\"tag\">ANTHROPIC</span></div>\n      <div style=\"font-family:'JetBrains Mono', monospace; font-size:12px; color:var(--text-soft); line-height:1.7; margin-top:10px;\">\n        Interview me with AskUserQuestion.<br>\n        Dig into the hard parts.<br>\n        Then write the spec into SPEC.md.\n      </div>\n    </div>\n  </div>\n</div>\n<div class=\"callout\">Then: <strong>fresh new session</strong> to execute. The plan shouldn't share context with the explorer.</div>\n\n%%%SLIDE 61%%%\n<h1>Spec-driven · 4 docs</h1>\n<div class=\"tree\">\n<div class=\"tree-row\">project/</div>\n<div class=\"tree-row\"><span class=\"tree-indent\">├── </span>src/</div>\n<div class=\"tree-row\"><span class=\"tree-indent\">├── tests/</span></div>\n<div class=\"tree-row\"><span class=\"tree-indent\">└── </span>.specs/</div>\n<div class=\"tree-row hl\"><span class=\"tree-indent\">    ├── </span><strong>PRD.md</strong><span class=\"tree-comment\">requirements, scope, success criteria</span></div>\n<div class=\"tree-row hl\"><span class=\"tree-indent\">    ├── </span><strong>architecture.md</strong><span class=\"tree-comment\">data model, API, decisions</span></div>\n<div class=\"tree-row hl\"><span class=\"tree-indent\">    ├── </span><strong>decisions.md</strong><span class=\"tree-comment\">ADR log, \"why\" &gt; \"what\"</span></div>\n<div class=\"tree-row hl\"><span class=\"tree-indent\">    └── </span><strong>features.json</strong><span class=\"tree-comment\">tracker, parseable by Claude</span></div>\n</div>\n\n%%%SLIDE 62%%%\n<h1>features.json</h1>\n\n```json\n{\n  \"features\": [{\n    \"id\": \"auth-sso\",\n    \"priority\": \"P0\",\n    \"acceptance\": [\"...\"],\n    \"passes\": {\n      \"unit\": true,\n      \"integration\": false,\n      \"e2e\": false\n    }\n  }]\n}\n```\n\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card success text-center\"><div class=\"card-num\">UNIT</div><div class=\"stat-num sm\" style=\"color:var(--green)\">✅</div><div class=\"card-note\">passing</div></div>\n  <div class=\"card danger text-center\"><div class=\"card-num\">INTEGRATION</div><div class=\"stat-num sm\" style=\"color:var(--red)\">❌</div><div class=\"card-note\">todo</div></div>\n  <div class=\"card danger text-center\"><div class=\"card-num\">E2E</div><div class=\"stat-num sm\" style=\"color:var(--red)\">❌</div><div class=\"card-note\">todo</div></div>\n</div>\n<div class=\"callout\">Claude parses it, ticks off as it goes. Dashboard + source of truth in one file.</div>\n\n%%%SLIDE 63%%%\n<h1>Stories + premortem</h1>\n<div class=\"vs\">\n  <div class=\"vs-side left\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">📖</span>Stories</div>\n    <div class=\"card-label\">Scenario per story</div>\n    <div class=\"card-body\">Acceptance criteria. Claude implements one at a time.</div>\n    <pre style=\"margin:12px 0 0; padding:10px !important; font-size:14px !important;\"><code>stories/\n  01-happy-path.md\n  02-expired-token.md\n  03-rate-limit.md</code></pre>\n  </div>\n  <div class=\"vs-divider\">+</div>\n  <div class=\"vs-side right\">\n    <div class=\"card-title\"><span style=\"font-size:1.2em\">⚠️</span>Premortem</div>\n    <div class=\"card-label\">Before prod</div>\n    <blockquote style=\"border:none; padding:0; font-size:18px; margin:8px 0;\">\n      <em>Imagine what can break. Find 20 issues even if all tests pass.</em>\n    </blockquote>\n    <div class=\"card-body\">Claude pattern-matches against known failures. Finds what tests miss.</div>\n  </div>\n</div>\n<h3>Skills & methods that pair well</h3>\n<div class=\"grid cols-4 gap-sm\">\n  <div class=\"card compact\"><div class=\"card-num\">superpowers</div><div class=\"card-note\">TDD · debug · review</div></div>\n  <div class=\"card compact\"><div class=\"card-num\">premortem</div><div class=\"card-note\">find 20 failures</div></div>\n  <div class=\"card compact\"><div class=\"card-num\">getshitdone</div><div class=\"card-note\">ship fast, iterate</div></div>\n  <div class=\"card compact\"><div class=\"card-num\">BMAD</div><div class=\"card-note\">spec-driven methodology</div></div>\n</div>\n%%%SLIDE 64%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:24px; text-transform:uppercase;\">NEXT UP</div>\n    <div style=\"font-size:80px; margin-bottom:24px;\">🔭</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Beyond</h1>\n  </div>\n</div>\n%%%SLIDE 65%%%\n<h1>The reset when it drifts</h1>\n<div class=\"flow-v\">\n  <div class=\"flow-v-step\"><span class=\"flow-v-num\">01</span><div class=\"flow-v-body\"><strong>Export</strong> the conversation</div></div>\n  <div class=\"flow-v-step\"><span class=\"flow-v-num\">02</span><div class=\"flow-v-body\"><strong>Paste into another model</strong> — GPT-5, Gemini, or a fresh Opus session</div></div>\n  <div class=\"flow-v-step\"><span class=\"flow-v-num\">03</span><div class=\"flow-v-body\"><strong>\"Critique this convo\"</strong> — where did it go wrong, what should the initial prompt have been?</div></div>\n  <div class=\"flow-v-step\"><span class=\"flow-v-num\">04</span><div class=\"flow-v-body\"><strong>Revert</strong> to the last good commit</div></div>\n  <div class=\"flow-v-step\"><span class=\"flow-v-num\">05</span><div class=\"flow-v-body\"><strong>Restart</strong> from the improved prompt</div></div>\n</div>\n<div class=\"callout\"><strong>Second set of eyes &gt; you, invested in your own conversation.</strong></div>\n\n%%%SLIDE 66%%%\n<h1>Beyond Claude Code</h1>\n<div class=\"grid cols-3 gap-sm\">\n  <div class=\"card\"><div class=\"card-num\">MERMAID</div><div class=\"card-body\">GPT, Gemini, Llama, Qwen — all trained on it</div></div>\n  <div class=\"card\"><div class=\"card-num\">AGENT SKILLS</div><div class=\"card-body\">Open standard · adopted by Cursor</div></div>\n  <div class=\"card\"><div class=\"card-num\">HOOKS + EXIT 2</div><div class=\"card-body\">Pure bash pattern · any agent CLI</div></div>\n  <div class=\"card\"><div class=\"card-num\">WORKTREES</div><div class=\"card-body\">Git, not Claude</div></div>\n  <div class=\"card\"><div class=\"card-num\">SPEC-DRIVEN</div><div class=\"card-body\">Methodology, not a tool</div></div>\n  <div class=\"card\"><div class=\"card-num\">MCP</div><div class=\"card-body\">Open standard · multi-vendor</div></div>\n</div>\n\n%%%SLIDE 67%%%\n<h1>Multi-model inside Claude Code</h1>\n\n```mermaid\nflowchart LR\n    CC[Claude Code<br>orchestrator]\n    CC -->|images, search| G[Gemini CLI]\n    CC -->|cross-model review| CX[Codex]\n    CC -->|offline, sensitive| O[Ollama + llama.cpp]\n    CC -->|fallback| AP[Alt provider]\n```\n\n<div class=\"callout\"><strong>Claude orchestrates. Local models do the grunt work.</strong> Transcription, summaries, semantic grep — no need to burn frontier tokens.</div>\n\n%%%SLIDE 68%%%\n<h1>What you're really investing in</h1>\n<div style=\"display:grid; grid-template-columns: 1fr 1fr; gap:40px; align-items:center; margin-top:24px;\">\n  <div>\n    <blockquote style=\"font-size:28px; line-height:1.35;\">\n      The real investment is <em>methodology</em> and <em>context engineering discipline</em>.<br>\n      <span style=\"color:#fafafa; font-style:normal;\">Not the tool.</span>\n    </blockquote>\n  </div>\n  <div style=\"text-align:center;\">\n    <svg viewBox=\"0 0 240 240\" width=\"240\" height=\"240\">\n      <polygon points=\"120,20 210,200 30,200\" fill=\"none\" stroke=\"#d97757\" stroke-width=\"1.5\"/>\n      <line x1=\"60\" y1=\"140\" x2=\"180\" y2=\"140\" stroke=\"#242424\" stroke-width=\"1\"/>\n      <line x1=\"90\" y1=\"80\" x2=\"150\" y2=\"80\" stroke=\"#242424\" stroke-width=\"1\"/>\n      <text x=\"120\" y=\"65\" text-anchor=\"middle\" font-family=\"Fraunces\" font-size=\"14\" fill=\"#fafafa\">Tool</text>\n      <text x=\"120\" y=\"115\" text-anchor=\"middle\" font-family=\"Fraunces\" font-size=\"16\" fill=\"#d4d4d4\">Method</text>\n      <text x=\"120\" y=\"175\" text-anchor=\"middle\" font-family=\"Fraunces\" font-size=\"20\" fill=\"#d97757\">Discipline</text>\n    </svg>\n  </div>\n</div>\n\n%%%SLIDE 69%%%\n<div style=\"display:flex; align-items:center; justify-content:center; height:100%;\">\n  <div class=\"text-center\">\n    <div style=\"font-size:80px; margin-bottom:24px;\">🚀</div>\n    <h1 style=\"font-size:80px; line-height:1;\">Demo time</h1>\n    <p style=\"font-size:28px; color:var(--muted); margin-top:20px;\">Let’s build a feature together</p>\n  </div>\n</div>\n%%%SLIDE 70%%%\n<h1>Live demo — <em style=\"color:#a238ff\">color mode</em></h1>\n<p>We’ll add a purple theme toggle to this very deck, using the workflow we just learned.</p>\n<div class=\"grid cols-2 gap-lg\" style=\"margin-top:24px;\">\n  <div>\n    <h3>The feature</h3>\n    <div class=\"card accent\" style=\"border-left-color:#a238ff;\">\n      <div class=\"card-label\" style=\"color:#a238ff;\">Switch accent from <span style=\"color:var(--accent);\">● orange</span> to <span style=\"color:#a238ff;\">● purple</span></div>\n      <div class=\"card-body\">CSS variable swap — <code>--accent: #a238ff</code><br>Toggle via keyboard shortcut or button</div>\n    </div>\n  </div>\n  <div>\n    <h3>Tools we’ll use</h3>\n    <div class=\"flow-v\">\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">01</span><div class=\"flow-v-body\"><strong>Plan mode</strong> · Shift+Tab × 2, design first</div></div>\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">02</span><div class=\"flow-v-body\"><strong>superpowers</strong> · TDD, write test then implement</div></div>\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">03</span><div class=\"flow-v-body\"><strong>Stop hook</strong> · type-check before done</div></div>\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">04</span><div class=\"flow-v-body\"><strong>CLAUDE.md</strong> · project conventions enforced</div></div>\n      <div class=\"flow-v-step\"><span class=\"flow-v-num\">05</span><div class=\"flow-v-body\"><strong>Vercel</strong> · push → auto-deploy → live</div></div>\n    </div>\n  </div>\n</div>\n%%%SLIDE 71%%%\n<div class=\"text-center\" style=\"padding:40px 0;\">\n  <div style=\"font-family:'JetBrains Mono',monospace; font-size:12px; letter-spacing:0.24em; color:var(--accent); margin-bottom:20px;\">NOW</div>\n  <h1 style=\"font-size:96px;\">Kahoot<br><em>time</em></h1>\n  <div class=\"grid cols-3 gap-lg\" style=\"margin-top:44px; max-width:700px; margin-left:auto; margin-right:auto;\">\n    <div class=\"stat\"><div class=\"stat-num\">10</div><div class=\"stat-label\">questions</div></div>\n    <div class=\"stat\"><div class=\"stat-num\">20s</div><div class=\"stat-label\">per question</div></div>\n    <div class=\"stat\"><div class=\"stat-num\">4</div><div class=\"stat-label\">choices</div></div>\n  </div>\n</div>\n\n%%%SLIDE 72%%%\n<h1>Three things to try tomorrow</h1>\n<div class=\"grid cols-3 gap-lg\">\n  <div class=\"card accent\">\n    <span style=\"font-size:1.2em\">📚</span>\n    <div class=\"card-num\">01 · CONTEXT</div>\n    <div class=\"card-label\">Mermaid diagram</div>\n    <div class=\"card-body\"><code>.claude/memory/diagrams/auth.md</code> — or equivalent for your critical flow. Alias <code>cdi</code> to load at startup.</div>\n  </div>\n  <div class=\"card accent\">\n    <span style=\"font-size:1.2em\">🛡️</span>\n    <div class=\"card-num\">02 · ENFORCEMENT</div>\n    <div class=\"card-label\">Stop hook</div>\n    <div class=\"card-body\">Type-check / lint. <code>exit 2</code> on failure. Claude is now forced to fix before stopping.</div>\n  </div>\n  <div class=\"card accent\">\n    <span style=\"font-size:1.2em\">📦</span>\n    <div class=\"card-num\">03 · LEVERAGE</div>\n    <div class=\"card-label\">A skill</div>\n    <div class=\"card-body\">Write one, or install one: <code>superpowers</code>, <code>premortem</code>, <code>frontend-design</code>.</div>\n  </div>\n</div>\n\n%%%SLIDE 73%%%\n<h1>Cheatsheet · Session & Modes</h1>\n<h3>Session</h3>\n<div class=\"kbd-list\">\n  <div class=\"kbd-row\"><span class=\"kbd\">/clear</span><span class=\"kbd-desc\">reset context</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/context</span><span class=\"kbd-desc\">see usage</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/usage</span><span class=\"kbd-desc\">plan quota</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/compact</span><span class=\"kbd-desc\">manual compact</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/resume</span><span class=\"kbd-desc\">named session</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/insights</span><span class=\"kbd-desc\">roast patterns</span></div>\n</div>\n<h3>Modes & models</h3>\n<div class=\"kbd-list\">\n  <div class=\"kbd-row\"><span class=\"kbd\">Shift+Tab</span><span class=\"kbd-desc\">cycle modes</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">Esc</span><span class=\"kbd-desc\">interrupt</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">Ctrl+S</span><span class=\"kbd-desc\">stash prompt</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">Ctrl+G</span><span class=\"kbd-desc\">edit plan</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/model opus|sonnet|haiku</span><span class=\"kbd-desc\">switch model</span></div>\n  <div class=\"kbd-row\"><span class=\"kbd\">/model opus[1m]</span><span class=\"kbd-desc\">1M context</span></div>\n</div>\n\n%%%SLIDE 74%%%\n<h1>Cheatsheet · CLI flags</h1>\n<div class=\"terminal\">\n  <div class=\"terminal-body\"><span class=\"comment\"># context</span>\n--append-system-prompt <span class=\"value\">\"&lt;txt&gt;\"</span>       <span class=\"comment\"># add to system prompt</span>\n--system-prompt <span class=\"value\">\"&lt;txt&gt;\"</span>              <span class=\"comment\"># replace system prompt</span>\n\n<span class=\"comment\"># modes</span>\n--agent <span class=\"value\">&lt;name&gt;</span>                       <span class=\"comment\"># direct sub-agent</span>\n--worktree <span class=\"value\">&lt;name&gt;</span>                    <span class=\"comment\"># isolated worktree</span>\n-p <span class=\"value\">\"&lt;prompt&gt;\"</span>                          <span class=\"comment\"># headless</span>\n--bare -p                            <span class=\"comment\"># CI mode, skip hooks/MCP</span>\n\n<span class=\"comment\"># isolation</span>\n--strict-mcp-config --mcp-config <span class=\"value\">&lt;f&gt;</span>  <span class=\"comment\"># full MCP isolation</span>\n--setting-sources <span class=\"value\">\"\"</span>                   <span class=\"comment\"># disable all conventions</span>\n--dangerously-skip-permissions       <span class=\"comment\"># local dev only</span>\n\n<span class=\"comment\"># forking</span>\n--fork-session --continue            <span class=\"comment\"># fork for A/B</span></div>\n</div>\n\n%%%SLIDE 75%%%\n<h1>Resources to bookmark</h1>\n<div class=\"grid cols-2 gap-sm\">\n  <div class=\"card\"><div class=\"card-title\"><span style=\"font-size:1.2em\">📖</span>Official</div><div class=\"card-body\"><code>code.claude.com/docs/en/best-practices</code></div></div>\n  <div class=\"card\"><div class=\"card-title\"><span style=\"font-size:1.2em\">📦</span>Curated</div><div class=\"card-body\"><code>github.com/hesreallyhim/awesome-claude-code</code></div></div>\n  <div class=\"card accent\"><div class=\"card-title\"><span style=\"font-size:1.2em\">⚡</span>Superpowers</div><div class=\"card-body\"><code>github.com/obra/superpowers</code></div></div>\n  <div class=\"card accent\"><div class=\"card-title\"><span style=\"font-size:1.2em\">⚡</span>RTK</div><div class=\"card-body\"><code>github.com/rtk-ai/rtk</code></div></div>\n  <div class=\"card\"><div class=\"card-title\"><span style=\"font-size:1.2em\">▶️</span>Lindquist course</div><div class=\"card-body\"><code>egghead.io/q/claude-code</code> · 47+ lessons</div></div>\n  <div class=\"card\"><div class=\"card-title\"><span style=\"font-size:1.2em\">▶️</span>Schoppik course</div><div class=\"card-body\"><code>learn.deeplearning.ai/courses/claude-code</code></div></div>\n  <div class=\"card\"><div class=\"card-title\"><span style=\"font-size:1.2em\">💬</span>HumanLayer</div><div class=\"card-body\"><code>humanlayer.dev/blog/writing-a-good-claude-md</code></div></div>\n  <div class=\"card\"><div class=\"card-title\"><span style=\"font-size:1.2em\">#️⃣</span>Mermaid deep dive</div><div class=\"card-body\"><code>mindstudio.ai/blog/mermaid-diagrams-claude-code</code></div></div>\n</div>\n\n%%%SLIDE 76%%%\n<div class=\"text-center\" style=\"padding:24px 0;\">\n  <div style=\"font-family:'JetBrains Mono',monospace; font-size:14px; letter-spacing:0.24em; color:var(--accent); margin-bottom:20px;\"></div>\n  <h1 style=\"font-size:56px; line-height:1.1;\">What will <em>you</em><br>try tomorrow?</h1>\n  <div style=\"margin-top:48px; padding-top:20px; border-top:1px solid var(--border); display:inline-block;\">\n    <div style=\"font-family:'Fraunces',serif; font-style:italic; font-size:26px; color:var(--text-soft);\">Thanks</div>\n    <div style=\"font-family:'JetBrains Mono',monospace; font-size:13px; letter-spacing:0.14em; color:var(--muted); margin-top:10px;\">Paul Cailly & Claude</div>\n  </div>\n</div>\n";
